module gpio_controller(  
    input wire clk,  
    input wire reset,  
    input wire control,  // 0 for read, 1 for write  
    input wire [7:0] data_in,  
    output reg [7:0] data_out  
);  
    reg [7:0] invalid_data;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            invalid_data <= 8'b0;  
            data_out <= 8'b0;  
        end else begin  
            if (control) begin  
                // Write mode  
                invalid_data <= data_in;  
            end else begin  
                // Read mode  
                data_out <= invalid_data;  
            end  
        end  
    end  
endmodule
